#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<string> fruits = {"Apple", "Banana", "Cherry"};

    // 1. Index loop:
    for (size_t i = 0; i < fruits.size(); i++) {
        cout << i << ": " << fruits[i] << endl;
    }

    // 2. Range-based for (preferred):
    cout << "--- range for ---" << endl;
    for (const auto& fruit : fruits) {
        cout << fruit << endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> v = {10, 20, 30, 40, 50};

    // Insert at position 2:
    v.insert(v.begin() + 2, 25);
    for (int x : v) cout << x << " ";
    cout << endl;

    // Erase position 0:
    v.erase(v.begin());
    for (int x : v) cout << x << " ";
    cout << endl;

    cout << "Front: " << v.front() << endl;
    cout << "Back: "  << v.back()  << endl;
    cout << "Empty: " << boolalpha << v.empty() << endl;

    return 0;
}

#include <iostream>
#include <array>
using namespace std;

int main() {
    // C array — legacy, avoid in new code:
    int cArr[5] = {1, 2, 3, 4, 5};
    cout << cArr[0] << endl;
    // cArr[10] = 99; — undefined behaviour, no error!

    // std::array — safe, STL-compatible:
    array<int, 5> arr = {10, 20, 30, 40, 50};
    cout << arr.size() << endl;
    cout << arr.at(2)  << endl;    // bounds checked
    cout << arr.front() << endl;
    cout << arr.back()  << endl;

    // Range-based for works too:
    for (int x : arr) cout << x << " ";
    cout << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>
using namespace std;

int main() {
    vector<int> scores = {95, 87, 73, 91, 68, 82};

    int sum = accumulate(scores.begin(), scores.end(), 0);
    int mn  = *min_element(scores.begin(), scores.end());
    int mx  = *max_element(scores.begin(), scores.end());
    double avg = static_cast<double>(sum) / scores.size();

    cout << "Sum: " << sum << endl;
    cout << "Min: " << mn  << endl;
    cout << "Max: " << mx  << endl;
    cout << "Avg: " << avg << endl;

    return 0;
}

